use std::path::PathBuf;
use std::time::Duration;

use tokio::sync::mpsc::Receiver;

pub struct Job {
    pub id: u64,
    pub config_path: PathBuf,
}

pub struct JobRunner {
    rx: Receiver<Job>,
    max_retries: u32,
}

impl JobRunner {
    pub fn new(rx: Receiver<Job>, max_retries: u32) -> Self {
        Self { rx, max_retries }
    }

    pub async fn run(mut self) {
        while let Some(job) = self.rx.recv().await {
            let mut attempt = 0;
            loop {
                match self.process(&job).await {
                    Ok(()) => break,
                    Err(_) if attempt < self.max_retries => {
                        attempt += 1;
                        let backoff = Duration::from_millis(200 * attempt as u64);
                        tokio::time::sleep(backoff).await;
                    }
                    Err(e) => {
                        tracing::error!(job = job.id, error = %e, "job failed");
                        break;
                    }
                }
            }
        }
    }

    async fn process(&self, job: &Job) -> std::io::Result<()> {
        let raw = tokio::fs::read(&job.config_path).await?;
        tracing::info!(job = job.id, bytes = raw.len(), "loaded job config");
        Ok(())
    }
}

